// node_conv_244 -- tiled-streaming pointwise (1x1) conv2d, stride=1.
//   IC=512, OC=256, IH=IW=28, OH=OW=28, MP=4, channel_tile=32.
//   IN_BEATS=16, OUT_BEATS=8, OC_PASSES=64, K_TOTAL=512.
//   Latency: IN_BEATS + OC_PASSES * (MP*K_TOTAL + 6)
//          = 16 + 64 * 2054 = 131472 cycles.
//
// Stride=1 pointwise: every input pixel is active (no skip filter), so the
// FSM flows directly LOAD -> RUNNING for every pixel, in raster order.
//
// Array writes (acc / biased / scaled) live in a sync-only always block to
// dodge the activation_memory_in_async_reset_block preflight gate. All
// scalar control / packed regs stay in the async-reset block A.
module node_conv_244 (
    input  wire         clk,
    input  wire         rst_n,
    input  wire         valid_in,
    output reg          ready_in,
    input  wire [255:0] data_in,
    output reg          valid_out,
    output reg  [255:0] data_out
);
    localparam IC = 512;
    localparam OC = 256;
    localparam IH = 28, IW = 28;
    localparam OH = 28, OW = 28;
    localparam KH = 1, KW = 1;
    localparam SH = 1, SW = 1;
    localparam K_TOTAL      = IC * KH * KW;
    localparam MP           = 4;
    localparam OC_PASSES    = (OC + MP - 1) / MP;
    localparam CHANNEL_TILE = 32;
    localparam IN_BEATS     = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam OUT_BEATS    = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam TILE_BITS    = CHANNEL_TILE * 8;

    localparam integer SCALE_MULT  = 28774;
    localparam integer SCALE_SHIFT = 22;

    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = 26;
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = ((ACC_W > BIAS_W) ? ACC_W : BIAS_W) + 1;
    localparam integer SCALE_MAG_W   = 16;
    localparam integer SCALE_CONST_W = SCALE_MAG_W + 1;
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;

    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    localparam ST_LOAD    = 3'd0;
    localparam ST_RUNNING = 3'd1;
    localparam ST_BIAS    = 3'd2;
    localparam ST_SCALE   = 3'd3;
    localparam ST_OUTPUT  = 3'd4;
    localparam ST_EMIT    = 3'd5;
    reg [2:0] state;

    (* rom_style = "block", ram_style = "block" *)
    reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *)
    reg signed [31:0] biases  [0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_244_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_244_bias.hex",   biases);
    end

    reg [IC*8-1:0] in_latch;
    reg [4:0]      in_beat_idx;
    reg [OC*8-1:0] out_pack;
    reg [3:0]      out_beat_idx;
    reg [4:0] pixel_row;
    reg [4:0] pixel_col;
    reg [5:0] oc_group;
    reg [1:0] lane_counter;
    reg [9:0] k_counter;
    reg       mac_done_issuing;
    reg [1:0] drain_count;

    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];

    reg signed [7:0]  weight_q1;
    reg signed [7:0]  in_byte_q1;
    reg [1:0]         lane_q1;
    reg               mac_valid_q1;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q2;
    reg [1:0]         lane_q2;
    reg               mac_valid_q2;

    reg signed [SCALED_W-1:0] v_tmp;
    integer init_i;
    integer a_lane;
    integer a_gid;
    integer b_i;
    integer b_lane;

    wire load_complete_now = (state == ST_LOAD) && valid_in && ready_in &&
                             (in_beat_idx == IN_BEATS - 1);
    wire next_pass_now     = (state == ST_OUTPUT) && (oc_group != OC_PASSES - 1);

    initial begin
        for (init_i = 0; init_i < MP; init_i = init_i + 1) begin
            acc[init_i]    = {ACC_W{1'b0}};
            biased[init_i] = {BIASED_W{1'b0}};
            scaled[init_i] = {SCALED_W{1'b0}};
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state            <= ST_LOAD;
            ready_in         <= 1'b1;
            valid_out        <= 1'b0;
            data_out         <= 256'b0;
            in_latch         <= {(IC*8){1'b0}};
            in_beat_idx      <= 5'd0;
            out_pack         <= {(OC*8){1'b0}};
            out_beat_idx     <= 4'd0;
            pixel_row        <= 5'd0;
            pixel_col        <= 5'd0;
            oc_group         <= 6'd0;
            lane_counter     <= 2'd0;
            k_counter        <= 10'd0;
            mac_done_issuing <= 1'b0;
            drain_count      <= 2'd0;
            weight_q1        <= 8'sd0;
            in_byte_q1       <= 8'sd0;
            lane_q1           <= 2'd0;
            mac_valid_q1     <= 1'b0;
            mul_q2           <= {PROD_W{1'b0}};
            lane_q2          <= 2'd0;
            mac_valid_q2     <= 1'b0;
            v_tmp            <= {SCALED_W{1'b0}};
        end else begin
            mac_valid_q1 <= 1'b0;
            mul_q2       <= $signed(weight_q1) * $signed(in_byte_q1);
            lane_q2      <= lane_q1;
            mac_valid_q2 <= mac_valid_q1;

            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    if (valid_in && ready_in) begin
                        in_latch[in_beat_idx*TILE_BITS +: TILE_BITS] <= data_in;
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx      <= 5'd0;
                            ready_in         <= 1'b0;
                            state            <= ST_RUNNING;
                            oc_group         <= 6'd0;
                            lane_counter     <= 2'd0;
                            k_counter        <= 10'd0;
                            mac_done_issuing <= 1'b0;
                            drain_count      <= 2'd0;
                        end else begin
                            in_beat_idx <= in_beat_idx + 1'b1;
                        end
                    end
                end

                ST_RUNNING: begin
                    if (!mac_done_issuing) begin
                        weight_q1    <= weights[(oc_group * MP + lane_counter) * K_TOTAL + k_counter];
                        in_byte_q1   <= $signed(in_latch[k_counter * 8 +: 8]);
                        lane_q1      <= lane_counter;
                        mac_valid_q1 <= 1'b1;
                        if (k_counter == K_TOTAL - 1) begin
                            k_counter <= 10'd0;
                            if (lane_counter == MP - 1) begin
                                lane_counter     <= 2'd0;
                                mac_done_issuing <= 1'b1;
                                drain_count      <= 2'd0;
                            end else begin
                                lane_counter <= lane_counter + 1'b1;
                            end
                        end else begin
                            k_counter <= k_counter + 1'b1;
                        end
                    end else begin
                        if (drain_count == 2'd2) begin
                            state            <= ST_BIAS;
                            mac_done_issuing <= 1'b0;
                            drain_count      <= 2'd0;
                        end else begin
                            drain_count <= drain_count + 1'b1;
                        end
                    end
                end

                ST_BIAS: begin
                    state <= ST_SCALE;
                end

                ST_SCALE: begin
                    state <= ST_OUTPUT;
                end

                ST_OUTPUT: begin
                    for (a_lane = 0; a_lane < MP; a_lane = a_lane + 1) begin
                        a_gid = oc_group * MP + a_lane;
                        v_tmp = (scaled[a_lane] +
                                 (scaled[a_lane][SCALED_W-1] ? SCALE_ROUND_HALF_M1
                                                             : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                        out_pack[a_gid * 8 +: 8] <= (v_tmp > 127)  ? 8'sd127 :
                                                    (v_tmp < -128) ? -8'sd128 :
                                                                     v_tmp[7:0];
                    end

                    if (oc_group == OC_PASSES - 1) begin
                        valid_out    <= 1'b1;
                        data_out     <= out_pack[0 +: TILE_BITS];
                        out_beat_idx <= 4'd1;
                        state        <= ST_EMIT;
                    end else begin
                        oc_group         <= oc_group + 1'b1;
                        lane_counter     <= 2'd0;
                        k_counter        <= 10'd0;
                        mac_done_issuing <= 1'b0;
                        drain_count      <= 2'd0;
                        state            <= ST_RUNNING;
                    end
                end

                ST_EMIT: begin
                    if (out_beat_idx == OUT_BEATS) begin
                        valid_out    <= 1'b0;
                        ready_in     <= 1'b1;
                        state        <= ST_LOAD;
                        out_beat_idx <= 4'd0;
                        oc_group     <= 6'd0;
                        if (pixel_row == OH - 1 && pixel_col == OW - 1) begin
                            pixel_row <= 5'd0;
                            pixel_col <= 5'd0;
                        end else if (pixel_col == OW - 1) begin
                            pixel_col <= 5'd0;
                            pixel_row <= pixel_row + 1'b1;
                        end else begin
                            pixel_col <= pixel_col + 1'b1;
                        end
                    end else begin
                        data_out     <= out_pack[out_beat_idx * TILE_BITS +: TILE_BITS];
                        out_beat_idx <= out_beat_idx + 1'b1;
                    end
                end

                default: begin
                    state <= ST_LOAD;
                end
            endcase
        end
    end

    always @(posedge clk) begin
        if (load_complete_now || next_pass_now) begin
            for (b_i = 0; b_i < MP; b_i = b_i + 1) begin
                acc[b_i] <= {ACC_W{1'b0}};
            end
        end else if (mac_valid_q2) begin
            acc[lane_q2] <= acc[lane_q2] + $signed(mul_q2);
        end

        if (state == ST_BIAS) begin
            for (b_lane = 0; b_lane < MP; b_lane = b_lane + 1) begin
                biased[b_lane] <= acc[b_lane] + $signed(biases[oc_group * MP + b_lane]);
            end
        end

        if (state == ST_SCALE) begin
            for (b_lane = 0; b_lane < MP; b_lane = b_lane + 1) begin
                scaled[b_lane] <= $signed(biased[b_lane]) * $signed(SCALE_MULT_CONST);
            end
        end
    end

endmodule
